package main

import (
	"encoding/gob"
	"fmt"
	"io/ioutil"
	"os"
	"path/filepath"
	"sync"
	"time"
)

type Session struct {
	UserID       string
	Preferences  map[string]interface{}
	Permissions  []string
	LastAccessed time.Time
}

type SessionManager struct {
	sessions map[string]*Session
	mu       sync.RWMutex
	dir      string
}

func NewSessionManager(dir string) (*SessionManager, error) {
	if err := os.MkdirAll(dir, 0700); err != nil {
		return nil, err
	}
	
	sm := &SessionManager{
		sessions: make(map[string]*Session),
		dir:      dir,
	}
	
	// Load existing sessions
	sm.loadSessions()
	
	return sm, nil
}

func (sm *SessionManager) CreateSession(userID string) (*Session, error) {
	session := &Session{
		UserID:       userID,
		Preferences:  make(map[string]interface{}),
		Permissions:  make([]string, 0),
		LastAccessed: time.Now(),
	}
	
	sm.mu.Lock()
	sm.sessions[userID] = session
	sm.mu.Unlock()
	
	// Save to disk
	if err := sm.saveSession(userID, session); err != nil {
		return nil, err
	}
	
	return session, nil
}

func (sm *SessionManager) GetSession(userID string) (*Session, bool) {
	sm.mu.RLock()
	defer sm.mu.RUnlock()
	
	session, exists := sm.sessions[userID]
	if !exists {
		return nil, false
	}
	
	// Update last accessed time
	session.LastAccessed = time.Now()
	
	// Save updated session
	go sm.saveSession(userID, session)
	
	return session, true
}

func (sm *SessionManager) saveSession(userID string, session *Session) error {
	filename := filepath.Join(sm.dir, userID+".gob")
	
	file, err := os.Create(filename)
	if err != nil {
		return err
	}
	defer file.Close()
	
	encoder := gob.NewEncoder(file)
	encoder.SetEscapeHTML(false)
	
	return encoder.Encode(session)
}

func (sm *SessionManager) loadSessions() {
	files, err := ioutil.ReadDir(sm.dir)
	if err != nil {
		return
	}
	
	for _, file := range files {
		if filepath.Ext(file.Name()) == ".gob" {
			userID := strings.TrimSuffix(file.Name(), ".gob")
			session, err := sm.loadSession(userID)
			if err == nil {
				sm.mu.Lock()
				sm.sessions[userID] = session
				sm.mu.Unlock()
			}
		}
	}
}

func (sm *SessionManager) loadSession(userID string) (*Session, error) {
	filename := filepath.Join(sm.dir, userID+".gob")
	
	file, err := os.Open(filename)
	if err != nil {
		return nil, err
	}
	defer file.Close()
	
	var session Session
	decoder := gob.NewDecoder(file)
	decoder.SetStrict(true)
	
	err = decoder.Decode(&session)
	if err != nil {
		return nil, err
	}
	
	return &session, nil
}

func (sm *SessionManager) UpdatePreferences(userID string, prefs map[string]interface{}) error {
	session, exists := sm.GetSession(userID)
	if !exists {
		return fmt.Errorf("session not found")
	}
	
	for key, value := range prefs {
		session.Preferences[key] = value
	}
	
	return sm.saveSession(userID, session)
}

func (sm *SessionManager) AddPermission(userID string, permission string) error {
	session, exists := sm.GetSession(userID)
	if !exists {
		return fmt.Errorf("session not found")
	}
	
	// Check if permission already exists
	for _, perm := range session.Permissions {
		if perm == permission {
			return nil
		}
	}
	
	session.Permissions = append(session.Permissions, permission)
	return sm.saveSession(userID, session)
}

func (sm *SessionManager) RemovePermission(userID string, permission string) error {
	session, exists := sm.GetSession(userID)
	if !exists {
		return fmt.Errorf("session not found")
	}
	
	for i, perm := range session.Permissions {
		if perm == permission {
			session.Permissions = append(session.Permissions[:i], session.Permissions[i+1:]...)
			break
		}
	}
	
	return sm.saveSession(userID, session)
}

func (sm *SessionManager) DeleteSession(userID string) error {
	sm.mu.Lock()
	delete(sm.sessions, userID)
	sm.mu.Unlock()
	
	filename := filepath.Join(sm.dir, userID+".gob")
	return os.Remove(filename)
}

func (sm *SessionManager) CleanupExpiredSessions(maxAge time.Duration) {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	
	now := time.Now()
	for userID, session := range sm.sessions {
		if now.Sub(session.LastAccessed) > maxAge {
			delete(sm.sessions, userID)
			filename := filepath.Join(sm.dir, userID+".gob")
			os.Remove(filename)
		}
	}
}

